import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS attack!')</script>";

        // Encode the user input using ESAPI to prevent XSS
        Encoder encoder = ESAPI.encoder();
        String encodedUserInput = encoder.encodeForHTML(userInput);

        // Output the sanitized user input to the HTML page
        System.out.println("<html>");
        System.out.println("<head><title>XSS Fixed Page</title></head>");
        System.out.println("<body>");
        System.out.println("<h1>Welcome, " + encodedUserInput + "</h1>");
        System.out.println("</body>");
        System.out.println("</html>");
    }
}

